import { useState, useEffect } from 'react';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { SummoningSeal } from './components/SummoningSeal';
import { Navigation } from './components/Navigation';
import { Hero } from './components/Hero';
import { ProductShowcase } from './components/ProductShowcase';
import { About } from './components/About';
import { Footer } from './components/Footer';
import { Cart } from './components/Cart';
import { AdminPanel } from './components/AdminPanel';

gsap.registerPlugin(ScrollTrigger);

function App() {
  const [showSeal, setShowSeal] = useState(true);
  const [showAdmin, setShowAdmin] = useState(false);

  // Check if user has already entered
  useEffect(() => {
    const hasEntered = sessionStorage.getItem('zeal-entered');
    if (hasEntered) {
      setShowSeal(false);
    }
  }, []);

  const handleEnter = () => {
    sessionStorage.setItem('zeal-entered', 'true');
    setShowSeal(false);
  };

  useEffect(() => {
    if (showSeal) return;

    const ctx = gsap.context(() => {
      const sections = gsap.utils.toArray<HTMLElement>('main > section, footer');

      sections.forEach((section) => {
        gsap.fromTo(
          section,
          { opacity: 0, y: 28 },
          {
            opacity: 1,
            y: 0,
            duration: 0.9,
            ease: 'power2.out',
            scrollTrigger: {
              trigger: section,
              start: 'top 82%',
              once: true,
            },
          }
        );
      });
    });

    return () => ctx.revert();
  }, [showSeal]);

  return (
    <div className="min-h-screen bg-[#050505] text-white font-sans selection:bg-[#a08040] selection:text-black">
      {/* Summoning Seal Loading Screen */}
      {showSeal && <SummoningSeal onEnter={handleEnter} />}

      {/* Main Content */}
      {!showSeal && (
        <>
          {/* Navigation */}
          <Navigation onOpenAdmin={() => setShowAdmin(true)} />

          {/* Main Sections */}
          <main>
            <Hero />
            <ProductShowcase />
            <About />
          </main>

          <Footer />

          {/* Cart Sidebar */}
          <Cart onCheckout={() => {}} />

          {/* Admin Panel */}
          {showAdmin && <AdminPanel onClose={() => setShowAdmin(false)} />}
        </>
      )}
    </div>
  );
}

export default App;
